-- Enrichment marathon batch: CodeRabbit, CodeSignal, codiga.io, Codility, CodSpeed, Cognizant, Coinbase, CoinMarketCap

-- ── CodeRabbit ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CodeRabbit is an AI-powered code review platform that automatically analyzes pull requests on GitHub, GitLab, Azure DevOps, and Bitbucket, leaving line-by-line, context-aware feedback. It combines large language models with static analysis and linters to catch bugs, security issues, and style problems before human reviewers get involved. Founded in 2023, it has become one of the most widely installed AI apps on the GitHub Marketplace.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, per-seat monthly or annual subscription billed per active pull request author$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans start at 24 USD per developer per month billed annually$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Walnut Creek, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CodeRabbit Review 2026: AI Code Review Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See what CodeRabbit does, how its AI PR reviews work, 2026 pricing plans, key features, pros and cons, and whether it fits your engineering team.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CodeRabbit is an AI-driven code review platform, founded in 2023 by Harjot Gill and headquartered in Walnut Creek, California. It integrates directly with GitHub, GitLab, Azure DevOps, and Bitbucket to automatically review pull requests, generating line-by-line comments, a natural-language summary of the change set, and a walkthrough that maps how modified files relate to one another. Under the hood, CodeRabbit combines large language models with more than a dozen integrated static analysis engines and linters (covering languages such as Python, JavaScript, TypeScript, Java, Go, Ruby, and C/C++) so it can flag both stylistic issues and deeper logic, security, and performance problems in the same pass. Reviewers and developers can converse with the CodeRabbit bot directly inside PR comments, asking it to explain a suggestion, generate a fix, or re-run a check after changes are pushed, which distinguishes it from purely static, rule-based linters. As of 2026, CodeRabbit reports more than 8,000 paying customers and use across 100,000-plus open-source projects and 2 million-plus repositories, and it holds a leading position on the GitHub Marketplace by install count. The company raised a 60 million dollar round in September 2025 at a 550 million dollar valuation, reflecting strong enterprise demand for AI-assisted code review as PR volume has grown alongside AI-assisted coding tools. Pricing is seat-based, charged per active PR author rather than total headcount, which lets organizations onboard incrementally. The Free tier offers a 14-day trial of paid features, unlimited public and private repository use, PR summarization, and IDE and CLI-based reviews. The Pro tier, at 24 dollars per developer per month billed annually, adds linter and SAST tool support, Jira and Linear integrations, an agentic chat interface, customizable reports, docstring generation, and a capped number of MCP connections and linked repositories. The Pro Plus tier, at 48 dollars per developer per month billed annually, layers on custom pre-merge checks, automated unit test generation, code simplification suggestions, merge-conflict resolution assistance, and an issue planner, along with higher usage limits. Enterprise pricing is custom and adds self-hosting, role-based access control, single sign-on, audit logging, API access, multi-org support, SLA-backed support, and a dedicated customer success manager, aimed at large engineering organizations with compliance requirements. A pay-as-you-go add-on removes review-volume caps, and a Slack-based agent is billed per minute of agent runtime. CodeRabbit competes against a growing set of AI code review tools including Qodo, Graphite's Diamond, Greptile, and GitHub Copilot's own review features, as well as traditional static analysis tools like SonarQube. Its core differentiators are the conversational chat interface embedded in PRs, configurable review profiles that reduce false positives, and integration with existing linter configurations so teams don't have to migrate rule sets. Typical adopters are software engineering teams that want to reduce reviewer fatigue and shorten PR cycle time, particularly teams shipping code quickly with AI pair-programming tools where PR volume has grown faster than senior-reviewer bandwidth. Because reviews run automatically on every push, teams commonly use CodeRabbit as a first-pass gate before a human reviewer weighs in, rather than as a full replacement for human code review.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '02acf2e5-4009-4310-aa4d-caf63f972e5f';

