-- ── codiga.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codiga was a static code analysis and automated code review platform for IDEs and CI/CD pipelines, founded in 2018. Datadog acquired Codiga in April 2023, and its static analysis technology has since been folded into Datadog's Code Security and Static Analysis product line rather than continuing as a standalone offering. The codiga.io domain now points visitors toward Datadog's static analysis tooling.$q$, short_description),
  pricing_model = COALESCE($q$Not applicable as an independent product; Codiga's technology is now part of Datadog's platform pricing$q$, pricing_model),
  starting_price = COALESCE($q$Not applicable, standalone Codiga pricing was discontinued after the Datadog acquisition$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (absorbed into Datadog, a public company with several thousand employees, following the 2023 acquisition)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (pre-acquisition)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Codiga.io in 2026: What Happened After the Datadog Acquisition$q$, seo_title),
  seo_meta_description = COALESCE($q$Codiga was a static code analysis tool acquired by Datadog in 2023. See what it did, what changed, and where its technology lives today.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codiga was a static code analysis and automated code review platform founded in 2018 by Julien Delange, designed to help engineering teams catch bugs, security vulnerabilities, and code-quality issues directly inside their IDE, through extensions for VS Code, JetBrains IDEs, and others, and inside CI/CD pipelines through integrations with GitHub, GitLab, Bitbucket, and Azure DevOps. Before its acquisition, Codiga offered real-time static analysis with support for a wide range of languages including Python, JavaScript, TypeScript, Java, PHP, Ruby, C#, Apex, Dockerfile, and Terraform, along with a library of reusable code snippets, customizable rulesets, and automated pull request review comments that flagged style, security, and maintainability issues without requiring teams to configure a separate linter for every language. Codiga also offered a code-quality dashboarding layer that let engineering managers track quality trends and technical debt across repositories over time. On April 17, 2023, Datadog announced it had acquired Codiga, and Datadog subsequently discontinued Codiga's standalone products, migrating relevant customers and shutting down independent billing. As of 2026, visiting codiga.io shows a banner stating that Codiga has joined Datadog, and traffic intended for static analysis is directed to sign up for Datadog's own Code Security and Static Analysis capabilities, which now incorporate static analysis techniques drawn from Codiga's original engine as part of Datadog's broader Application Security Management and Code Security suite. This means that, unlike an actively maintained standalone SaaS product, Codiga no longer has independent pricing, a standalone free tier, or its own actively promoted IDE marketplace listings; instead, organizations that want equivalent static-analysis capability today are directed toward Datadog's unified observability and security platform, which is priced separately according to Datadog's own usage-based pricing models rather than Codiga's original per-seat pricing. For a directory or comparison context, Codiga is best understood historically: it competed with tools such as SonarQube, Semgrep, and DeepSource in the static analysis category, and its acquisition is a representative example of the broader consolidation of standalone developer-tooling startups into larger observability and security platforms during 2022 and 2023. Teams researching Codiga today should evaluate Datadog's current Code Security and Static Analysis product directly rather than expecting to sign up for Codiga as an independent service, since new account creation, standalone support, and Codiga-branded pricing are no longer available. This entry is maintained primarily for historical and comparison accuracy, since Codiga still appears in older buyer's guides, review sites, and integration marketplaces even though the product itself has been retired in its original form.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '77d2c00f-b93d-4ada-a9e5-3d02c9527db3';

