-- ── Codility ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codility is a technical skills assessment and coding interview platform founded in 2009 that helps engineering and talent teams evaluate developer candidates through automated coding tests, take-home tasks, and live technical interviews. It is used by large enterprises including GitHub, SpaceX, Tesla, SAP, and major banks to standardize technical hiring at scale. Codility is headquartered in London, United Kingdom.$q$, short_description),
  pricing_model = COALESCE($q$Tiered annual or monthly subscription priced by number of assessment invites per year$q$, pricing_model),
  starting_price = COALESCE($q$Starter plan from 1,200 USD per year for 120 assessment invites$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Codility Review 2026: Pricing, Features and How It Works$q$, seo_title),
  seo_meta_description = COALESCE($q$What Codility does, its 2026 Starter, Scale, and Custom pricing, key features for technical hiring, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codility is a technical skills assessment platform founded in 2009 and headquartered in London, United Kingdom, built to help engineering and talent acquisition teams evaluate the coding ability of job candidates and, in some deployments, benchmark the skills of existing employees. The platform provides a library of more than 1,300 coding tasks and real-work simulations spanning 80-plus programming languages and frameworks, including Java, Python, JavaScript, TypeScript, SQL, C++, and React, and supports several assessment formats: timed algorithmic challenges (CodeCheck), take-home projects that resemble realistic engineering work, and live, collaborative technical interviews (CodeLive) where an interviewer and candidate can pair-program together with automated test execution and code-history playback. Codility's scoring engine analyzes not just whether a candidate's solution passes tests but also code quality, time complexity, and edge-case handling, producing standardized reports that let hiring teams compare candidates objectively rather than relying purely on subjective interviewer impressions. The platform includes plagiarism and similarity detection to flag copied solutions, proctoring features for remote assessment integrity, and integrations with applicant tracking systems such as Greenhouse and Lever, along with an API for custom hiring workflow automation. Codility's customer base skews toward large, well-known technology and enterprise organizations, with publicly referenced customers including GitHub, SpaceX, Tesla, EY, LSEG, SAP, Barclays, and Citi, reflecting its historical positioning as an enterprise-grade assessment tool rather than a lightweight startup screening tool. Pricing is structured around the number of assessment invites purchased per year rather than a flat per-seat fee. The Starter plan costs 1,200 dollars per year, billed annually only, and includes up to 120 invites per year and a single platform user, aimed at smaller hiring teams or companies just standardizing their process. The Scale plan costs roughly 500 dollars per month, or about 5,000 dollars per year billed annually (a discount versus paying monthly), and includes up to 300 invites per year (25 per month) and three platform users, suited to mid-sized companies hiring engineers regularly. A Custom or Enterprise tier is quote-only and adds unlimited platform users, single sign-on, deeper ATS integrations, higher or unlimited invite volumes, and dedicated support, aimed at large enterprises running high-volume technical hiring pipelines. Codility competes most directly with CodeSignal, HackerRank, and CoderByte in the technical assessment space; it is generally regarded as one of the more established, enterprise-oriented platforms in the category given its long track record and Fortune 500-level customer references. Companies typically adopt Codility to reduce time-to-hire, cut down on unproductive onsite technical interviews, remove interviewer bias from early-stage screening, and create a consistent, auditable record of how each candidate was evaluated, which is increasingly important for both hiring-quality and compliance reasons at large organizations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e322b3d3-fb73-45a5-98a5-5284be52351d';

