-- ── CodSpeed ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CodSpeed is a continuous performance testing and benchmarking platform that runs automated, noise-reduced benchmarks inside CI pipelines and reports performance regressions directly on pull requests. Founded in 2023 and based in Paris, France, it is built by a small Techstars-backed team and integrates with GitHub Actions and other CI providers to give engineering teams visibility into performance changes before code merges.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, per-seat monthly or annual subscription with metered add-ons$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 5 users and unlimited for open source projects; Pro plan from 15 USD per user per month$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CodSpeed Review 2026: Continuous Benchmarking Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$What CodSpeed does, its 2026 Free, Pro, and Enterprise pricing, CI performance testing features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CodSpeed is a continuous performance testing platform, founded by Arthur Pastel, Adrien Cacciaguerra, and Guillaume Lagrange and headquartered in Paris, France, that helps software teams catch performance regressions before they reach production by running automated benchmarks as part of the CI/CD pipeline rather than only in ad hoc local testing. The company was built through Techstars and has raised early-stage venture funding from investors including Kima Ventures and Better Angle. CodSpeed's core idea is that traditional wall-clock benchmarking is too noisy to run reliably in shared CI infrastructure, so it instead uses CPU-instruction-level simulation, counting actual instructions executed rather than measuring elapsed time, to produce deterministic, reproducible benchmark results even when CI runners have variable, shared hardware performance. When a pull request is opened, CodSpeed's GitHub Action, also available for other CI providers, runs the project's benchmark suite, compares the results against the base branch, and posts a report as a PR check and comment showing which functions got faster or slower and by how much, similar in spirit to how code coverage tools report diffs. This lets engineering teams treat performance the same way they treat test coverage or type-checking: as an automated, mandatory-if-desired gate on every change, rather than something only investigated after users report slowness. CodSpeed supports common language ecosystems including Python, Rust, JavaScript and TypeScript, and Go, integrates with popular benchmarking libraries and frameworks, and offers macro-benchmark runners for wall-clock, database, and GPU-bound workloads as an add-on for cases where instruction-count simulation is not the right fit. Pricing follows a freemium, per-seat model. The Free plan supports up to five users, with unlimited usage for open-source projects, unlimited benchmark runs and repositories, three months of historical data, PR reporting and checks, CPU simulation and wall-time instruments, and 600 macro-runner minutes per month. The Pro plan costs 15 dollars per user per month, billed monthly or annually, and unlocks unlimited history, priority support, and metered add-ons such as additional macro-runner minutes at 0.032 dollars per minute beyond the included allotment, plus database and GPU instruments. A 14-day free trial of Pro is available. The Enterprise plan is custom-priced and adds SSO and SAML, granular role management, SOC 2 Type II compliance reporting, on-premise or self-hosted deployment, a performance data API, custom macro-runner capacity, dedicated bare-metal runners with 16-core ARM64 CPUs and 32GB RAM, and SLA-backed support, targeting larger organizations with strict compliance or infrastructure requirements. CodSpeed is used most heavily by open-source library maintainers and performance-sensitive engineering teams, such as those building databases, web frameworks, compilers, and data-processing libraries, who need confidence that a given pull request has not silently introduced a performance regression, and it is commonly adopted alongside existing CI/CD and code-review tooling as a complementary, performance-focused check rather than a replacement for functional testing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f478ddc4-f63a-48a1-bc0d-6d01460ea3f7';

