-- ── Coinbase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Coinbase is a publicly traded (NASDAQ: COIN) cryptocurrency exchange and financial technology platform that lets individuals and institutions buy, sell, store, and transact in digital assets. Founded in 2012 and headquartered in New York, it operates a regulated retail app, an advanced trading platform, custody and institutional services, and its own Layer 2 blockchain network, Base.$q$, short_description),
  pricing_model = COALESCE($q$Transaction-based fees (spread plus a flat or tiered percentage fee) with an optional paid membership for reduced fees$q$, pricing_model),
  starting_price = COALESCE($q$Free to create an account; standard app trading fees range from about 1.49 to 3.99 percent per trade; Coinbase One membership starts at 4.99 USD per month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Approximately 5,000-7,400 employees (count varies by reporting period)$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Coinbase in 2026: Fees, Features and How It Works$q$, seo_title),
  seo_meta_description = COALESCE($q$What Coinbase does, its 2026 fee structure, Coinbase One membership tiers, key features, pros, cons and FAQs for buying and trading crypto.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Coinbase is a publicly traded cryptocurrency exchange and financial technology company, founded in 2012 by Brian Armstrong and Fred Ehrsam, that provides regulated infrastructure for individuals, businesses, and institutions to buy, sell, store, stake, and transact in digital assets such as Bitcoin, Ethereum, and a wide range of other cryptocurrencies and tokens. The company went public on NASDAQ in April 2021 under the ticker symbol COIN via a direct listing, becoming one of the first major cryptocurrency companies to do so, and it is headquartered in New York, New York, with a globally distributed workforce. Coinbase operates two primary consumer-facing trading interfaces: the standard Coinbase app, designed for beginners, which bundles a spread of roughly 0.50 percent into its quoted prices plus a separate fee that varies by payment method, commonly cited in the 1.49 to 3.99 percent range depending on funding source, and Coinbase Advanced Trade, an order-book-based interface for more active traders priced on a maker and taker model that starts around 0.40 percent maker and 0.60 percent taker at the lowest 30-day volume tier and declines toward 0.00 and 0.05 percent at very high volume tiers, with no additional spread. Coinbase One is an optional paid membership, restructured in recent years into multiple tiers, commonly cited as a Basic tier around 4.99 dollars per month, a Preferred tier around 29.99 dollars per month, and a Premium tier around 299.99 dollars per month, which waives standard-app trading fees up to a monthly volume cap, offers a rebate on Advanced Trade fees, provides boosted staking rewards, zero-fee trades on integrated decentralized exchanges, and account protection of up to 250,000 dollars against unauthorized access; the underlying spread still applies even with a membership. Beyond retail trading, Coinbase offers Coinbase Prime and custody services for institutions, a self-custody wallet product, a debit card, staking services, and Base, Coinbase's own Ethereum Layer 2 blockchain network that supports decentralized applications. Coinbase is regulated as a money services business and licensed exchange across the jurisdictions in which it operates, and it publishes regular financial disclosures as a public company under SEC oversight, including quarterly shareholder letters and 10-Q and 10-K filings. Its main competitors include Kraken, Binance, Gemini, and a growing set of decentralized exchanges, and it differentiates itself primarily on regulatory compliance, insurance and security posture, ease of use for mainstream and first-time crypto buyers, and integration with traditional banking rails. Coinbase's employee count has fluctuated with market cycles and reported layoffs and rehiring in past years, with figures cited in 2026 ranging from roughly 5,000 to over 7,000 depending on the reporting period and whether contractors are included. Coinbase is best understood as a regulated, publicly traded financial technology company operating in the digital-asset space, comparable in regulatory posture to a brokerage, and it operates as licensed financial infrastructure for buying, holding, and transacting in cryptocurrency.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7ddd07fe-32b0-4a5b-bf05-2226553c7e22';

