-- ── CoinMarketCap ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CoinMarketCap is a cryptocurrency market data platform that tracks prices, market capitalization, trading volume, and other metrics for tens of thousands of digital assets across thousands of exchanges. Founded in 2013 in New York by Brandon Chez, it was acquired by Binance in 2020 but operates as an editorially independent business. It offers free public data alongside a tiered developer API.$q$, short_description),
  pricing_model = COALESCE($q$Freemium website with a tiered, credit-based developer API subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free public website and basic API access; paid API plans start at roughly 29 USD per month billed annually (Hobbyist tier)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (operates as part of Binance's global organization)$q$, company_size),
  headquarters = COALESCE($q$New York, United States (founding headquarters); now operates as part of Binance's global organizational structure$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CoinMarketCap in 2026: Features, API Pricing and FAQs$q$, seo_title),
  seo_meta_description = COALESCE($q$What CoinMarketCap does, its 2026 API pricing tiers, key features, Binance ownership, pros, cons and frequently asked questions.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CoinMarketCap is a cryptocurrency market data and price-tracking platform founded in May 2013 by Brandon Chez in Long Island City, Queens, New York, built originally to give crypto investors a single, comprehensive place to see live prices, market capitalization rankings, and trading volume across the fast-growing number of cryptocurrencies and exchanges. The platform grew to become one of the most widely cited sources of cryptocurrency price data on the internet, referenced by financial news outlets, research firms, and, per the company's own description, used by government agencies for research purposes. On March 31, 2020, Binance Holdings Limited, the world's largest cryptocurrency exchange, acquired CoinMarketCap in a deal estimated at 300 to 400 million dollars. Both companies have stated that CoinMarketCap continues to operate as an editorially independent business: Binance does not influence CoinMarketCap's rankings, methodology, or listed data, and CoinMarketCap does not influence Binance's operations, according to statements from both companies. As of 2026, CoinMarketCap's core free product includes real-time and historical price charts for tens of thousands of cryptocurrencies and tokens, market capitalization and trading-volume rankings, a portfolio and watchlist tracker, DexScan, which covers decentralized exchange market data spanning 70-plus blockchain networks, NFT collection tracking, a Fear and Greed Index and other market-sentiment indicators, ETF tracking for Bitcoin and Ethereum investment products, and CMC Academy, an educational content hub covering blockchain and cryptocurrency fundamentals. Beyond the consumer-facing website and mobile app, CoinMarketCap operates a developer-facing Crypto API used by exchanges, trading platforms, financial data terminals, and research tools to pull structured price, market, and metadata for cryptocurrencies programmatically. The API is offered on a tiered subscription model: a Basic tier requires contacting sales for a custom quote; a Hobbyist tier costs 348 dollars per month, or 29 dollars per month billed annually; a Startup tier costs 948 dollars per month, or 79 dollars per month annually; a Standard tier costs 3,588 dollars per month; a Professional tier costs 8,388 dollars per month, or 699 dollars per month annually; and an Enterprise tier is custom-quoted for the highest-volume use cases. CoinMarketCap also supports keyless, no-account API endpoints for limited public data and a pay-per-request access model via the x402 protocol at 0.01 USDC per request, aimed at lightweight or automated integrations that don't need a full subscription. CoinMarketCap's main competitors in the market-data category include CoinGecko and Messari, and various exchange-run data pages, and it differentiates itself primarily through the sheer breadth of assets and exchanges tracked, brand recognition built up since 2013, and the DexScan product for on-chain and decentralized-exchange data that complements its traditional centralized-exchange price aggregation. CoinMarketCap is best described as reference infrastructure for the cryptocurrency industry rather than a trading venue itself: it does not custody funds or execute trades, and its core value is data aggregation, ranking, and market transparency for investors, developers, media, and researchers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3a04a471-783c-4f17-abc2-93c4160543da';

