INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$Long sales cycles typical of enterprise consulting, not a self-serve product$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$What does Cognizant do?$q$, $q$Cognizant is a global IT services and consulting company that helps enterprises modernize technology, migrate to the cloud, adopt AI, and run large-scale digital transformation programs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$Is Cognizant a software product or a services company?$q$, $q$Cognizant is a professional services and consulting company; it does not sell a fixed self-service software subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$Where is Cognizant headquartered?$q$, $q$Cognizant is headquartered in Teaneck, New Jersey, United States.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$How large is Cognizant?$q$, $q$Cognizant employs roughly 351,000 people worldwide as of 2026 and is publicly traded on NASDAQ under the ticker CTSH.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$How is Cognizant priced?$q$, $q$Cognizant pricing is negotiated per client through custom statements of work and managed-services contracts; it does not publish list pricing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$What industries does Cognizant serve?$q$, $q$Cognizant serves banking and financial services, healthcare and life sciences, insurance, manufacturing, retail, and communications, media, and technology clients, among others.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$What is Cognizant's AI strategy?$q$, $q$Cognizant positions itself as an AI builder, embedding generative and agentic AI into client engagements and offering dedicated Secure AI Services to help enterprises govern AI systems.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$Who are Cognizant's main competitors?$q$, $q$Cognizant competes with Accenture, Infosys, TCS, Wipro, IBM Consulting, and Capgemini.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$Enterprise IT modernization$q$, $q$Large enterprises engage Cognizant to modernize legacy applications and infrastructure at scale.$q$, $q$Large enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$Compliance-aware digital transformation$q$, $q$Regulated industries such as banking, healthcare, and insurance use Cognizant's industry-specific platforms for transformation projects.$q$, $q$Regulated industry organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$Governing enterprise AI adoption$q$, $q$Organizations adopting generative or agentic AI engage Cognizant's Secure AI Services to govern and scale these systems safely.$q$, $q$Enterprises adopting AI$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$cognizant-service-lines$q$, $q$Cognizant's Core Service Lines$q$, 2, ARRAY[$q$Cognizant organizes its business around IT consulting and digital engineering, application development and modernization, cloud infrastructure services, business process services, and data and AI consulting.$q$, $q$It also builds industry-specific solutions for banking, healthcare, insurance, manufacturing, retail, and communications and media clients, reflecting a vertical-industry approach to enterprise consulting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$cognizant-ai-strategy$q$, $q$Cognizant's AI Strategy$q$, 2, ARRAY[$q$Cognizant has positioned itself as an AI builder, embedding generative AI and agentic AI capabilities directly into client engagements rather than offering AI as a separate bolt-on service.$q$, $q$In May 2026 the company launched Secure AI Services to help enterprises govern and scale agentic AI systems safely, and in April 2026 it agreed to acquire Astreya Partners for approximately 600 million dollars to strengthen its AI infrastructure capabilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f915015-7de1-4fdb-a477-34888a09649c', $q$how-cognizant-engagements-work$q$, $q$How Cognizant Client Engagements Work$q$, 2, ARRAY[$q$Cognizant does not sell a fixed-price product; engagements are negotiated directly with a client's procurement and IT leadership through statements of work, managed-services contracts, or staff-augmentation arrangements.$q$, $q$This means pricing varies significantly by project scope, industry, and contract length, and is not published in a standard rate card.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Beginner-friendly retail trading app$q$, $q$Simple interface for buying, selling, and holding cryptocurrency with straightforward pricing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Coinbase Advanced Trade$q$, $q$Order-book trading interface with maker and taker pricing for more active traders.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Coinbase One membership$q$, $q$Paid tiers that waive standard-app fees up to a cap and add account protection and staking boosts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Institutional custody and prime brokerage$q$, $q$Coinbase Prime and custody services built for institutional clients.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Self-custody wallet$q$, $q$A separate wallet product that lets users hold private keys themselves.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Staking services$q$, $q$Lets users earn staking rewards on supported proof-of-stake assets.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Coinbase Card$q$, $q$A debit card that allows spending directly from crypto balances.$q$, 6);
