INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Standard app fees are high relative to Advanced Trade or competing exchanges$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$The underlying spread still applies even for Coinbase One members on the standard app$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Fee structure across the app, Advanced Trade, and Coinbase One tiers can be confusing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Customer support has historically drawn criticism for response times$q$, 3);
