INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$What is Coinbase?$q$, $q$Coinbase is a publicly traded cryptocurrency exchange and financial technology platform that lets users buy, sell, store, and transact in digital assets.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Is Coinbase regulated?$q$, $q$Yes, Coinbase operates as a regulated money services business and licensed exchange in the jurisdictions where it operates, and it is a publicly traded company under SEC oversight.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$How much does Coinbase charge in fees?$q$, $q$The standard app charges roughly 1.49 to 3.99 percent per trade including spread, while Advanced Trade uses maker/taker pricing starting around 0.40/0.60 percent that declines at higher volume.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$What is Coinbase One?$q$, $q$Coinbase One is a paid membership, offered in multiple tiers starting around 4.99 dollars per month, that waives standard-app trading fees up to a cap and adds other benefits like account protection.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$What is the difference between the standard Coinbase app and Coinbase Advanced Trade?$q$, $q$The standard app is simplified for beginners with a bundled spread and flat-style fee, while Advanced Trade is an order-book interface with lower, volume-tiered maker/taker fees for active traders.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Does Coinbase offer a self-custody wallet?$q$, $q$Yes, Coinbase offers a separate self-custody wallet product in addition to its exchange-hosted accounts.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$What is Base?$q$, $q$Base is Coinbase's own Ethereum Layer 2 blockchain network that supports decentralized applications.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Is Coinbase safe to store cryptocurrency on?$q$, $q$Coinbase maintains a security and insurance program and is subject to regulatory oversight as a public company, though as with any exchange, users should evaluate self-custody options for long-term holdings.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Buying and holding digital assets$q$, $q$First-time crypto buyers use the standard Coinbase app for a simple way to purchase and hold digital assets.$q$, $q$First-time crypto buyers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Active trading with lower fees$q$, $q$Active traders use Coinbase Advanced Trade to access volume-tiered maker/taker pricing.$q$, $q$Active traders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Institutional custody and treasury services$q$, $q$Institutions and businesses use Coinbase Prime for custody, prime brokerage, and treasury management.$q$, $q$Institutions and businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Coinbase One Basic$q$, $q$4.99 USD per month$q$, $q$monthly$q$, NULL, $q$["Waived standard-app trading fees up to a monthly cap","Boosted staking rewards","Account protection"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Coinbase One Preferred$q$, $q$29.99 USD per month$q$, $q$monthly$q$, NULL, $q$["All Basic tier benefits","Higher fee waiver caps","Additional rebates"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$Coinbase One Premium$q$, $q$299.99 USD per month$q$, $q$monthly$q$, NULL, $q$["All Preferred tier benefits","Highest fee waiver caps","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$coinbase-products-overview$q$, $q$Coinbase Products Overview$q$, 2, ARRAY[$q$Coinbase offers a beginner-friendly retail app, a more advanced order-book trading interface called Advanced Trade, institutional custody and prime brokerage services, a self-custody wallet, and staking for supported assets.$q$, $q$It also operates Base, its own Ethereum Layer 2 blockchain network that supports decentralized applications, extending Coinbase's role beyond trading into blockchain infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$coinbase-fee-structure$q$, $q$Coinbase Fee Structure$q$, 2, ARRAY[$q$The standard Coinbase app bundles a roughly 0.50 percent spread into quoted prices plus a payment-method fee, commonly in the 1.49 to 3.99 percent range, making it simple but relatively expensive for frequent traders.$q$, $q$Coinbase Advanced Trade uses a maker and taker fee schedule based on 30-day trading volume, starting around 0.40/0.60 percent and declining toward 0.00/0.05 percent at the highest volume tiers, with no added spread.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ddd07fe-32b0-4a5b-bf05-2226553c7e22', $q$coinbase-one-membership$q$, $q$Coinbase One Membership$q$, 2, ARRAY[$q$Coinbase One is a paid membership available in multiple tiers that waives standard-app trading fees up to a monthly volume cap and provides a rebate on Advanced Trade fees, boosted staking rewards, and account protection.$q$, $q$The membership does not eliminate the underlying spread on standard-app trades, so cost-conscious frequent traders often still prefer Advanced Trade pricing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Real-time and historical price data$q$, $q$Tracks prices, charts, and historical data for tens of thousands of cryptocurrencies and tokens.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Market capitalization and volume rankings$q$, $q$Ranks assets by market capitalization and trading volume across thousands of exchanges.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Portfolio and watchlist tracking$q$, $q$Lets users track their own holdings and watch specific assets over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$DexScan decentralized exchange data$q$, $q$Covers on-chain, decentralized exchange market data across 70-plus blockchain networks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$NFT collection tracking$q$, $q$Tracks pricing and activity data for NFT collections.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Fear and Greed Index$q$, $q$A sentiment indicator summarizing overall market mood based on multiple data inputs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$CMC Academy$q$, $q$Educational content covering blockchain and cryptocurrency fundamentals.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Tiered developer Crypto API$q$, $q$Programmatic access to market data with free keyless endpoints, pay-per-request access, and paid subscription tiers.$q$, 7);
