INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Free tier covers most casual investor use cases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$DexScan extends coverage into decentralized and on-chain markets$q$, 3);
