INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Ownership by Binance raises independence questions for some users, even if operationally separate$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Paid API tiers can be expensive for high-volume commercial use, with the Professional tier priced over 8,000 dollars per month at list price$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Data quality and self-reported metrics from smaller exchanges can vary$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Rankings have historically drawn scrutiny over trading-volume reporting methodology across the industry$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Does not execute trades or custody assets itself, so users must still use a separate exchange$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Company size and internal operations are not transparently disclosed$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Who owns CoinMarketCap?$q$, $q$CoinMarketCap has been owned by Binance Holdings Limited since Binance acquired it in March 2020, though both companies state it operates as an editorially independent business.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Is CoinMarketCap free to use?$q$, $q$Yes, the core website and app are free for tracking prices, market caps, and portfolios; a paid tiered API is available for developers who need programmatic access.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$How much does the CoinMarketCap API cost?$q$, $q$Paid API tiers range from about 29 dollars per month (Hobbyist, billed annually) up to 699 dollars per month (Professional, billed annually), with custom Basic and Enterprise pricing available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$When was CoinMarketCap founded?$q$, $q$CoinMarketCap was founded in May 2013 by Brandon Chez in Long Island City, Queens, New York.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Is CoinMarketCap the same company as Binance?$q$, $q$No. Binance acquired CoinMarketCap in 2020, but the two companies state CoinMarketCap operates as an editorially independent business separate from Binance's exchange operations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$What is DexScan on CoinMarketCap?$q$, $q$DexScan is CoinMarketCap's tool for tracking decentralized exchange market data across more than 70 blockchain networks.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Can I trade cryptocurrency directly on CoinMarketCap?$q$, $q$No, CoinMarketCap is a data and reference platform; it does not custody funds or execute trades itself.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$How accurate is CoinMarketCap's market data?$q$, $q$CoinMarketCap aggregates data from thousands of exchanges and is widely cited by media and researchers, though volume and liquidity metrics from smaller or less regulated exchanges can vary in reliability.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Tracking prices and portfolio value$q$, $q$Individual crypto investors use CoinMarketCap's free tools to monitor prices and manage a personal portfolio.$q$, $q$Individual crypto investors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Integrating market data into applications$q$, $q$Developers and trading platforms use the CoinMarketCap Crypto API to pull structured price and market data programmatically.$q$, $q$Developers and trading platforms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Citing market data in research and reporting$q$, $q$Journalists, analysts, and researchers reference CoinMarketCap's rankings and historical data in their work.$q$, $q$Researchers and journalists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Hobbyist$q$, $q$29 USD per month$q$, $q$annual$q$, NULL, $q$["Higher API call limits than free keyless access","Historical data access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Startup$q$, $q$79 USD per month$q$, $q$annual$q$, NULL, $q$["Increased API rate limits","Additional data endpoints"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Standard$q$, $q$3,588 USD per month$q$, $q$monthly$q$, NULL, $q$["Higher-volume API access","Expanded endpoint coverage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Professional$q$, $q$699 USD per month$q$, $q$annual$q$, NULL, $q$["High-volume commercial API access","Priority data endpoints"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Highest-volume API access","Custom SLAs and support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$coinmarketcap-core-features$q$, $q$CoinMarketCap Core Features$q$, 2, ARRAY[$q$CoinMarketCap tracks real-time and historical prices, market capitalization, and trading volume for tens of thousands of cryptocurrencies and tokens across thousands of exchanges.$q$, $q$It also offers portfolio tracking, DexScan for decentralized exchange data across 70-plus blockchain networks, NFT tracking, sentiment indicators like the Fear and Greed Index, and ETF tracking for Bitcoin and Ethereum products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$coinmarketcap-binance-ownership$q$, $q$CoinMarketCap's Ownership by Binance$q$, 2, ARRAY[$q$Binance acquired CoinMarketCap in March 2020 in a deal estimated at 300 to 400 million dollars, but both companies state that CoinMarketCap continues to operate as an editorially independent business.$q$, $q$Binance does not influence CoinMarketCap's rankings or listed data, and CoinMarketCap does not influence Binance's exchange operations, according to public statements from both companies.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a04a471-783c-4f17-abc2-93c4160543da', $q$coinmarketcap-api-pricing$q$, $q$CoinMarketCap API Pricing$q$, 2, ARRAY[$q$CoinMarketCap's developer API is priced in tiers: Hobbyist at 29 dollars per month billed annually, Startup at 79 dollars per month annually, Standard at 3,588 dollars per month, and Professional at 699 dollars per month billed annually, with custom Basic and Enterprise tiers available.$q$, $q$The platform also supports keyless public endpoints and pay-per-request access via the x402 protocol for lightweight integrations that don't require a subscription.$q$]::text[], 2);
